package com.aadil.jobtracker.security;import javax.crypto.KeyGenerator;import javax.crypto.SecretKey;import java.security.NoSuchAlgorithmException;import java.util.Base64;public class SecretKeyGenerator {    public static void main(String[] args) throws NoSuchAlgorithmException {        KeyGenerator keyGenerator = KeyGenerator.getInstance("HmacSHA256");        SecretKey key = keyGenerator.generateKey();        String base64 = Base64.getEncoder().encodeToString(key.getEncoded());        System.out.println(base64);    }}